DarkRPUI=DarkRPUI or {}; DarkRPUI.Scoreboard=DarkRPUI.Scoreboard or {}; local cursor=false
local function setCursor(v) cursor=v; gui.EnableScreenClicker(v) end
function DarkRPUI.Scoreboard.Close() local f=DarkRPUI.Scoreboard.Frame; DarkRPUI.Scoreboard.Frame=nil; setCursor(false); if IsValid(f) then f:Remove() end end
function DarkRPUI.Scoreboard.Open() if IsValid(DarkRPUI.Scoreboard.Frame) then return end local f=DarkRPUI.UI.CreateFrame("SERVER ROSTER",1120,760); DarkRPUI.Scoreboard.Frame=f; f:SetKeyboardInputEnabled(false); local body=vgui.Create("DPanel",f); body:Dock(FILL); body:DockMargin(86,88,18,18); body.Paint=nil; local rail=vgui.Create("DPanel",f); rail:SetPos(18,88); rail:SetSize(54,f:GetTall()-106); rail.Paint=function(_,w,h) DarkRPUI.UI.RoundedBox(16,0,0,w,h,DarkRPUI.Color("sidebarDark")) end; local pages={{"players","👥",DarkRPUI.Scoreboard.BuildPlayerList},{"columns","▥",DarkRPUI.Scoreboard.BuildColumnEditor},{"ranks","◆",DarkRPUI.Scoreboard.BuildRankEditor},{"settings","⚙",DarkRPUI.Scoreboard.BuildSettings}}; local active="players"; for _,pg in ipairs(pages) do local b=DarkRPUI.UI.MakeIconButton(rail,pg[2],function() active=pg[1]; pg[3](body) end); b:Dock(TOP); b:DockMargin(8,8,8,0); b:SetTall(38); b.ActiveFunc=function() return active==pg[1] end end; DarkRPUI.Scoreboard.BuildPlayerList(body) end
hook.Add("ScoreboardShow","DarkRPUI.Scoreboard.Show",function() if DarkRPUI.Config.EnableScoreboard then DarkRPUI.Scoreboard.Open(); return false end end)
hook.Add("ScoreboardHide","DarkRPUI.Scoreboard.Hide",function() DarkRPUI.Scoreboard.Close() end)
hook.Add("Think","DarkRPUI.Scoreboard.Cursor",function() if IsValid(DarkRPUI.Scoreboard.Frame) then if not input.IsKeyDown(KEY_TAB) then DarkRPUI.Scoreboard.Close() elseif input.IsMouseDown(MOUSE_RIGHT) and not cursor then setCursor(true) end end end)
